#include <bits/stdc++.h>
using namespace std;
struct dot
{
    int x,y,z;
};
dot a[50005];
bool func(dot b,dot c)
{
    return b.z<c.z;
}
int main() 
{
    int n;
    double sum=0;
    cin>>n;
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].x>>a[i].y>>a[i].z;
    }
    sort(a,a+n,func);
    for(int i=0;i<=n-2;i++)
    {
        sum+=sqrt(pow((a[i].x-a[i+1].x),2)+pow((a[i].y-a[i+1].y),2)+pow((a[i].z-a[i+1].z),2));
    }
    printf("%.3f",sum);
    return 0;
}
